4	const scenario = JSON.parse(readFileSync(0, "utf8"));
5	const remainingCapByPolicy = new Map<number, number>();
6	const results = scenario.steps.map(
7	  (step: { type: string; policy?: { items: unknown[] } | number; incident?: { cause: string; damages: unknown[] } }) => {
8	    if (step.type === "quote") {
9	      const { premium } = quote({
10	        customer: scenario.customer,
11	        items: (step.policy as { items: unknown[] }).items as never,
12	      });
13	      return { premium };
14	    }
15	    if (step.type === "claim") {
16	      const policyIndex = step.policy as number;
17	      const referenced = scenario.steps[policyIndex] as { policy: { items: unknown[] } };
18	      const items = referenced.policy.items;
19	      const tracked = remainingCapByPolicy.get(policyIndex);
20	      const claimInput: { items: unknown[]; remainingCap?: number } = { items };
21	      if (tracked !== undefined) claimInput.remainingCap = tracked;
22	      const { payout, remainingCap } = claim(
23	        claimInput as never,
24	        step.incident as never,
25	      );
26	      remainingCapByPolicy.set(policyIndex, remainingCap);
27	      return { payout, remainingCap };
28	    }
29	    return {};
30	  },
31	);
32	process.stdout.write(JSON.stringify({ results }));
