const scenario = JSON.parse(readFileSync(0, "utf8"));
const remainingCapByPolicy = new Map<number, number>();
let priorContracts = scenario.customer.priorContracts;
const results = scenario.steps.map(
  (step: { type: string; policy?: { items: unknown[] } | number; incident?: { cause: string; damages: unknown[] } }) => {
    if (step.type === "quote") {
      const { premium } = quote({
        customer: { ...scenario.customer, priorContracts },
        items: (step.policy as { items: unknown[] }).items as never,
      });
      priorContracts += 1;
      return { premium };
    }
